Возврат НовыеЗначения;
КонецЕсли;
Если НовыеЗначения = Неопределено Тогда
Возврат ИсходныйМассив;
КонецЕсли;

// Преобразуем массивы в списки
ИсходныйСписок = Новый СписокЗначений;
Для Каждого Элемент Из ИсходныйМассив Цикл
ИсходныйСписок.Добавить(Элемент);
КонецЦикла;
НовыеСписок = Новый СписокЗначений;
Для Каждого Элемент Из НовыеЗначения Цикл
НовыеСписок.Добавить(Элемент);
КонецЦикла;

// Объединяем и сортируем список
ОбъединенныйСписок = ИсходныйСписок.Скопировать();
ОбъединенныйСписок.ДобавитьВсе(НовыеСписок);
ОбъединенныйСписок.СортироватьПоЗначению();

// Возвращаем результат как массив
Возврат ОбъединенныйСписок.ВернутьЗначения(); КонецФункции

Функция ВернутьОбъединенныйОтсортированныйМассив(ИсходныйМассив, НовыеЗначения) Экспорт

	ОтсортированныеНовыеЗначения = Новый Массив;

	Для Каждого Значение Из НовыеЗначения Цикл
		ОтсортированныеНовыеЗначения.Добавить(Значение);
	КонецЦикла;

	Если ОтсортированныеНовыеЗначения.Количество() > 1 Тогда
		БыстраяСортировкаМассива(ОтсортированныеНовыеЗначения, 0, ОтсортированныеНовыеЗначения.Количество() - 1);
	КонецЕсли;

	Результат = Новый Массив;

	ИндексИсходного = 0;
	ИндексНовых = 0;

	КоличествоИсходного = ИсходныйМассив.Количество();
	КоличествоНовых = ОтсортированныеНовыеЗначения.Количество();

	Пока ИндексИсходного < КоличествоИсходного И ИндексНовых < КоличествоНовых Цикл

		Если ИсходныйМассив[ИндексИсходного] <= ОтсортированныеНовыеЗначения[ИндексНовых] Тогда
			Результат.Добавить(ИсходныйМассив[ИндексИсходного]);
			ИндексИсходного = ИндексИсходного + 1;
		Иначе
			Результат.Добавить(ОтсортированныеНовыеЗначения[ИндексНовых]);
			ИндексНовых = ИндексНовых + 1;
		КонецЕсли;

	КонецЦикла;

	Пока ИндексИсходного < КоличествоИсходного Цикл
		Результат.Добавить(ИсходныйМассив[ИндексИсходного]);
		ИндексИсходного = ИндексИсходного + 1;
	КонецЦикла;

	Пока ИндексНовых < КоличествоНовых Цикл
		Результат.Добавить(ОтсортированныеНовыеЗначения[ИндексНовых]);
		ИндексНовых = ИндексНовых + 1;
	КонецЦикла;

	Возврат Результат;

КонецФункции

Процедура БыстраяСортировкаМассива(МассивЗначений, ЛеваяГраница, ПраваяГраница)

	ЛевыйИндекс = ЛеваяГраница;
	ПравыйИндекс = ПраваяГраница;
	ОпорноеЗначение = МассивЗначений[Цел((ЛеваяГраница + ПраваяГраница) / 2)];

	Пока ЛевыйИндекс <= ПравыйИндекс Цикл

		Пока МассивЗначений[ЛевыйИндекс] < ОпорноеЗначение Цикл
			ЛевыйИндекс = ЛевыйИндекс + 1;
		КонецЦикла;

		Пока МассивЗначений[ПравыйИндекс] > ОпорноеЗначение Цикл
			ПравыйИндекс = ПравыйИндекс - 1;
		КонецЦикла;

		Если ЛевыйИндекс <= ПравыйИндекс Тогда

			ВременноеЗначение = МассивЗначений[ЛевыйИндекс];
			МассивЗначений[ЛевыйИндекс] = МассивЗначений[ПравыйИндекс];
			МассивЗначений[ПравыйИндекс] = ВременноеЗначение;

			ЛевыйИндекс = ЛевыйИндекс + 1;
			ПравыйИндекс = ПравыйИндекс - 1;

		КонецЕсли;

	КонецЦикла;

	Если ЛеваяГраница < ПравыйИндекс Тогда
		БыстраяСортировкаМассива(МассивЗначений, ЛеваяГраница, ПравыйИндекс);
	КонецЕсли;

	Если ЛевыйИндекс < ПраваяГраница Тогда
		БыстраяСортировкаМассива(МассивЗначений, ЛевыйИндекс, ПраваяГраница);
	КонецЕсли;

КонецПроцедуры

Функция ОбъединитьОтсортированныеМассивы(ИсходныйМассив, НовыеЗначения)
	Перем Результат;
	Результат = Новый Массив;

	// Копируем элементы исходного массива (он уже отсортирован)
	Если ТипЗнч(ИсходныйМассив) = Тип("Массив") Тогда
		Для И = 0 По ИсходныйМассив.Количество() - 1 Цикл
			Результат.Добавить(ИсходныйМассив.Получить(И));
		КонецЦикла;
	КонецЕсли;

	// Если новых значений нет — вернуть копию исходного массива
	Если НЕ (ТипЗнч(НовыеЗначения) = Тип("Массив")) Тогда
		Возврат Результат;
	КонецЕсли;

	// Вставляем каждое новое значение в отсортированный результирующий массив
	Для И = 0 По НовыеЗначения.Количество() - 1 Цикл
		Перем Значение, Лев, Прав, Середина, ТекЗнч;
		Значение = НовыеЗначения.Получить(И);

		Лев = 0;
		Прав = Результат.Количество();
		Пока Лев < Прав Цикл
			Середина = Цел((Лев + Прав) / 2);
			ТекЗнч = Результат.Получить(Середина);
			Если ТекЗнч <= Значение Тогда
				Лев = Середина + 1;
			Иначе
				Прав = Середина;
			КонецЕсли;
		КонецЦикла;

		Результат.Вставить(Лев, Значение);
	КонецЦикла;

	Возврат Результат;
КонецФункции

Функция СлитьИОтсортировать(ИсходныйМассив, НовыеЗначения)
    Результат = Новый Массив;

    Для каждого Элемент Из ИсходныйМассив Цикл
        Результат.Добавить(Элемент);
    КонецЦикла;

    Для каждого Элемент Из НовыеЗначения Цикл
        Результат.Добавить(Элемент);
