Функция ОбъединитьОтсортированныеМассивы(ИсходныйМассив, НовыеЗначения) Экспорт

	Результат = Новый Массив;

	// Сортируем копию массива новых значений, исходный массив не изменяется
	СписокЗначений = Новый СписокЗначений;
	СписокЗначений.ЗагрузитьЗначения(НовыеЗначения);
	СписокЗначений.СортироватьПоЗначению();
	ОтсортированныеНовые = СписокЗначений.ВыгрузитьЗначения();

	// Слияние двух отсортированных массивов
	ИндексИсходного = 0;
	ИндексНовых = 0;
	КоличествоИсходных = ИсходныйМассив.Количество();
	КоличествоНовых = ОтсортированныеНовые.Количество();

	Пока ИндексИсходного < КоличествоИсходных И ИндексНовых < КоличествоНовых Цикл
		Если ИсходныйМассив[ИндексИсходного] <= ОтсортированныеНовые[ИндексНовых] Тогда
			Результат.Добавить(ИсходныйМассив[ИндексИсходного]);
			ИндексИсходного = ИндексИсходного + 1;
		Иначе
			Результат.Добавить(ОтсортированныеНовые[ИндексНовых]);
			ИндексНовых = ИндексНовых + 1;
		КонецЕсли;
	КонецЦикла;

	Пока ИндексИсходного < КоличествоИсходных Цикл
		Результат.Добавить(ИсходныйМассив[ИндексИсходного]);
		ИндексИсходного = ИндексИсходного + 1;
	КонецЦикла;

	Пока ИндексНовых < КоличествоНовых Цикл
		Результат.Добавить(ОтсортированныеНовые[ИндексНовых]);
		ИндексНовых = ИндексНовых + 1;
	КонецЦикла;

	Возврат Результат;

КонецФункции
```

