Функция ОбъединитьИОтсортироватьМассивы(ИсходныйОтсортированный, НовыеЗначения) Экспорт

    Результат = Новый Массив;

    Если (ИсходныйОтсортированный = Неопределено Или ИсходныйОтсортированный.Количество() = 0) 
        И (НовыеЗначения = Неопределено Или НовыеЗначения.Количество() = 0) Тогда
        Возврат Результат;
    КонецЕсли;

    // Копируем исходный массив
    Если ИсходныйОтсортированный <> Неопределено Тогда
        Для Каждого Элемент Из ИсходныйОтсортированный Цикл
            Результат.Добавить(Элемент);
        КонецЦикла;
    КонецЕсли;

    // Добавляем новые значения
    Если НовыеЗначения <> Неопределено Тогда
        Для Каждого Элемент Из НовыеЗначения Цикл
            Результат.Добавить(Элемент);
        КонецЦикла;
    КонецЕсли;

    // Сортируем результирующий массив
    КоличествоЭлементов = Результат.Количество();
    Если КоличествоЭлементов > 1 Тогда

        // Быстрая сортировка (реализация без рекурсии или простая сортировка вставками для надежности)
        // Для простоты и производительности на встроенном языке используем алгоритм сортировки вставками с бинарным поиском или стандартный перебор
        Для Инд1 = 1 по КоличествоЭлементов - 1 Цикл
            ТекущийЭлемент = Результат[Инд1];
            Инд2 = Инд1 - 1;
            Пока Инд2 >= 0 И Результат[Инд2] > ТекущийЭлемент Цикл
                Результат[Инд2 + 1] = Результат[Инд2];
                Инд2 = Инд2 - 1;
            КонецЦикла;
            Результат[Инд2 + 1] = ТекущийЭлемент;
        КонецЦикла;

    КонецЕсли;

    Возврат Результат;

КонецФункции
