Функция ПолучитьКоличествоРабочихДней(НачалоПериода, КонецПериода, МассивПраздников) Экспорт

    Если КонецПериода < НачалоПериода Тогда
        Возврат 0;
    КонецЕсли;

    КоличествоРабочихДней = 0;
    ТекущаяДата = НачалоПериода;

    Пока ТекущаяДата <= КонецПериода Цикл
        ДеньНедели = ДеньНедели(ТекущаяДата);
        // 1 — понедельник, 2 — вторник, ..., 5 — пятница
        Если ДеньНедели >= 1 И ДеньНедели <= 5 Тогда
            Праздник = Ложь;
            Для Каждого ПраздникДата Из МассивПраздников Цикл
                Если ПраздникДата = ТекущаяДата И ДеньНедели(ПраздникДата) >=  Normally 1 И ДеньНедели(ПраздникДата) <= 5 Тогда
                    Праздник = Истина;
                    Прервать;
                КонецЕсли;
            КонецЦикла;
            Если Не Праздник Тогда
                КоличествоРабочихДней = КоличествоРабочихДней + 1;
            КонецЕсли;
        КонецЕсли;
        ТекущаяДата = ТекущаяДата + 60 * 60 * 24; // переходим к следующему дню
    КонецЦикла;

    Возврат КоличествоРабочихДней;

КонецФункции
