Функция ПолучитьЧислоРабочихДней(ДатаНачала, ДатаКонца, МассивПраздников)

	Если ДатаКонца < ДатаНачала Тогда
		Возврат 0;
	КонецЕсли;

	КоличествоДней = ДатаКонца - ДатаНачала + 1;
	РабочихДней = 0;

	Для Счетчик = 0 По КоличествоДней - 1 Цикл
		ТекущаяДата = ДатаНачала + Счетчик;
		ДеньНедели = Формат(ТекущаяДата, "ДДММГГГГ ЧЧ:ММ:СС ЧН")[1]; // Получаем день недели (1 - Понедельник, 7 - Воскресенье)

		Если ДеньНедели <> 7 И ДеньНедели <> 6 Тогда // Проверяем, что это будний день (не суббота и не воскресенье)
			ЯвляетсяПраздником = Ложь;
			Для Каждого Праздник Из МассивПраздников Цикл
				Если ТекущаяДата = Праздник Тогда
					ЯвляетсяПраздником = Истина;
					Прервать;
				КонецЕсли;
			КонецЦикла;

			Если НЕ ЯвляетсяПраздником Тогда
				РабочихДней = РабочихДней + 1;
			КонецЕсли;
		КонецЕсли;
	КонецЦикла;

	Возврат РабочихДней;

