				И ДеньНедели(ДатаПраздника) <= 5 Тогда

				ПраздничныеДаты.Вставить(ДатаПраздника, Истина);

			КонецЕсли;
		КонецЦикла;
	КонецЕсли;

	КоличествоРабочихДней = 0;
	ТекущаяДата = НачалоПериода;

	Пока ТекущаяДата <= КонецПериода Цикл

		Если ДеньНедели(ТекущаяДата) <= 5
			И ПраздничныеДаты.Получить(ТекущаяДата) = Неопределено Тогда

			КоличествоРабочихДней = КоличествоРабочихДней + 1;

