Функция КоличествоРабочихДней(ДатаНач, ДатаКон, МассивПраздников) Экспорт
	// Проверки и приведение дат к началу дня
	Если НЕ ЗначениеЗаполнено(ДатаНач) ИЛИ НЕ ЗначениеЗаполнено(ДатаКон) Тогда
		Возврат 0;
	КонецЕсли;
	ДатаНач = Дата(Год(ДатаНач), Месяц(ДатаНач), День(ДатаНач));
	ДатаКон = Дата(Год(ДатаКон), Месяц(ДатаКон), День(ДатаКон));
	Если ДатаКон < ДатаНач Тогда
		Возврат 0;
	КонецЕсли;

	// Подготовка множества праздников (без времени)
	Если НЕ ЗначениеЗаполнено(МассивПраздников) Тогда
		МассивПраздников = Новый Массив;
	КонецЕсли;
	Праздники = Новый Соответствие;
	Для Каждого Праздник Из МассивПраздников Цикл
		Если ЗначениеЗаполнено(Праздник) Тогда
			П = Дата(Год(Праздник), Месяц(Праздник), День(Праздник));
			Если НЕ Праздники.Содержит(П) Тогда
				Праздники.Вставить(П, Истина);
			КонецЕсли;
		КонецЕсли;
	КонецЦикла;

	// Подсчёт рабочих дней (понедельник-пятница -> дни недели 2..6)
	Результат = 0;
	Тек = ДатаНач;
	Пока Тек <= ДатаКон Цикл
		Дн = ДеньНедели(Тек);
		Если Дн >= 2 И Дн <= 6 Тогда
			Если НЕ Праздники.Содержит(Тек) Тогда
				Результат = Результат + 1;
			КонецЕсли;
		КонецЕсли;
		Тек = Тек + 1;
	КонецЦикла;

	Возврат Результат;
