Функция РабочиеДниВПериоде(ДатаНачала, ДатаКонца, Праздники) Экспорт

    Если ДатаКонца < ДатаНачала Тогда
        Возврат 0;
    КонецЕсли;

    // --- Подсчёт количества будних дней в периоде ---
    ВсеДни = (ДатаКонца - ДатаНачала) / 86400 + 1;
    Недели = Цел(ВсеДни / 7);
    Остаток = ВсеДни - Недели * 7;
    Будни = Недели * 5;

    ДННачала = ДеньНедели(ДатаНачала); // 1=Пн … 5=Пт, 6=Сб, 7=Вс
    Для Сч = 0 По Остаток - 1 Цикл
        ТекДН = ДННачала + Сч;
        Если ТекДН > 7 Тогда
            ТекДН = ТекДН - 7;
        КонецЕсли;
        Если ТекДН <= 5 Тогда
            Будни = Будни + 1;
        КонецЕсли;
    КонецЦикла;

    // --- Вычитаем праздники, попавшие в период на будний день ---
    Для Каждого ДатаПраздника Из Праздники Цикл
        Если ДатаПраздника >= ДатаНачала И ДатаПраздника <= ДатаКонца Тогда
            Если ДеньНедели(ДатаПраздника) <= 5 Тогда
                Будни = Будни - 1;
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Макс(Будни, 0);

КонецФункции
