Функция ПеревернутьСловаВСтроке(ИсходнаяСтрока)

	Если НЕ ЗначениеЗаполнено(ИсходнаяСтрока) Тогда
		Возврат "";
	КонецЕсли;

	// Удаляем лишние пробелы в начале и конце, а также заменяем множественные пробелы на одиночные
	ОчищеннаяСтрока = СокрЛП(СокрП(СтрЗаменить(ИсходнаяСтрока, Символы.ПС, " ")));
	Пока Найти(ОчищеннаяСтрока, "  ") > 0 Цикл
		ОчищеннаяСтрока = СтрЗаменить(ОчищеннаяСтрока, "  ", " ");
	КонецЦикла;

	Если НЕ ЗначениеЗаполнено(ОчищеннаяСтрока) Тогда
		Возврат "";
	КонецЕсли;

	// Разбиваем строку на массив слов
	МассивСлов = РазделитьСтроку(ОчищеннаяСтрока, " ");

	// Переворачиваем массив слов
	МассивСлов.Сортировать(ТипСортировки.ПоУбыванию);

	// Собираем строку обратно, разделяя слова одним пробелом
	Результат = "";
	Для Индекс = 0 По МассивСлов.Количество() - 1 Цикл
		Если Индекс > 0 Тогда
			Результат = Результат + " ";
		КонецЕсли;
		Результат = Результат + МассивСлов[Индекс];
	КонецЦикла;

	Возврат Результат;

КонецФункции

// Вспомогательная функция для разбиения строки на массив
// (встроенная функция РазделитьСтроку отсутствует в старых версиях платформы)
Функция РазделитьСтроку(СтрокаРазделитель, Разделитель)
	Массив = Новый Массив;
	Позиция = 1;
	Пока Позиция <= СтрДлина(СтрокаРазделитель) Цикл
		Найдено = Найти(СтрокаРазделитель, Разделитель, Позиция);
		Если Найдено = 0 Тогда
			Массив.Добавить(Сред(СтрокаРазделитель, Позиция));
			Прервать;
		Иначе
			Массив.Добавить(Сред(СтрокаРазделитель, Позиция, Найдено - Позиция));
			Позиция = Найдено + СтрДлина(Разделитель);
		КонецЕсли;
	КонецЦикла;
	Возврат Массив;
КонецФункции
```

