Результат = Источник.ПолучитьЗначение();
Если Результат = "" Тогда
Возврат "";
КонецЕсли;
Результат = СтрУбратьЛишниеПробелы(Результат);
Возврат СтрШаблон(Результат,"~",Разделитель);
