	Результат = "";

	Индекс = Слова.Количество() - 1;
	Пока Индекс >= 0 Цикл

		Если Результат <> "" Тогда
			Результат = Результат + " ";
		КонецЕсли;

		Результат = Результат + Слова[Индекс];
		Индекс = Индекс - 1;

	КонецЦикла;

	Возврат Результат;

