	Если ЗначениеЗаполнено(ИсходнаяСтрока) = Ложь Тогда
		ИсходнаяСтрока = "";
	КонецЕсли;

	Масс = СтрРазделить(ИсходнаяСтрока, " ");
	Слова = Новый Массив;
	Для Каждого Эл Из Масс Цикл
		Если Эл <> "" Тогда
			Слова.Добавить(Эл);
		КонецЕсли;
	КонецЦикла;

	Если Слова.Количество() = 0 Тогда
		Возврат "";
	КонецЕсли;

	Результат = "";
	Для Инд = Слова.Количество() - 1 По 0 Шаг -1 Цикл
		Если Результат = "" Тогда
			Результат = Слова[Инд];
		Иначе
			Результат = Результат + " " + Слова[Инд];
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;
