Функция СтепеньПоМодулю(Основание, Показатель, Модуль)

    Если Модуль = 1 Тогда
        Возврат 0;
    КонецЕсли;

    Если Показатель = 0 Тогда
        Возврат 1;
    КонецЕсли;

    Результат = 1;
    ТекущееОснование = Основание % Модуль;

    Пока Показатель > 0 Цикл
        Если Показатель % 2 = 1 Тогда
            Результат = (Результат * ТекущееОснование) % Модуль;
