Функция УмножитьПоМодулю(Множитель1, Множитель2, Модуль)

	Результат = 0;
	Слагаемое = Множитель1 % Модуль;
	Множитель = Множитель2;

	Пока Множитель > 0 Цикл

		Если Множитель % 2 = 1 Тогда
			Если Результат >= Модуль - Слагаемое Тогда
				Результат = Результат - (Модуль - Слагаемое);
			Иначе
				Результат = Результат + Слагаемое;
			КонецЕсли;
		КонецЕсли;

		Множитель = Цел(Множитель / 2);

		Если Множитель > 0 Тогда
			Если Слагаемое >= Модуль - Слагаемое Тогда
				Слагаемое = Слагаемое - (Модуль - Слагаемое);
			Иначе
				Слагаемое = Слагаемое + Слагаемое;
			КонецЕсли;
		КонецЕсли;

	КонецЦикла;

	Возврат Результат;

