	Для Каждого Строка ИЗ ТаблицаЗначений Цикл
		ЗначениеГруппировки = Строка[КолонкаГруппировки];
		СуммаСтроки = Строка[КолонкаСуммирования];

		НайденнаяСтрока = НайтиСтрокуПоЗначению(НоваяТаблица, КолонкаГруппировки, ЗначениеГруппировки);

		Если НайденнаяСтрока = Неопределено Тогда
			НоваяСтрока = НоваяТаблица.Добавить();
			НоваяСтрока[КолонкаГруппировки] = ЗначениеГруппировки;
			НоваяСтрока["Сумма"] = СуммаСтроки;
		Иначе
			НайденнаяСтрока["Сумма"] = НайденнаяСтрока["Сумма"] + СуммаСтроки;
		КонецЕсли;
	КонецЦикла;

	Возврат НоваяТаблица;

