Функция СгруппироватьТаблицуЗначений(ИсходнаяТаблица, ИмяКолонкиГруппировки, ИмяЧисловойКолонки)
    НоваяТаблица = Новый ТаблицаЗначений;
    ТипКолонкиГруппировки = ИсходнаяТаблица.Колонки[ИмяКолонкиГруппировки].ТипЗначения;
    НоваяТаблица.Колонки.Добавить("ЗначениеГруппировки", ТипКолонкиГруппировки);
    НоваяТаблица.Колонки.Добавить("Сумма", Новый ОписаниеТипов("Число"));

    СоответствиеСумм = Новый Соответствие;

    Для Каждого СтрокаИсходной Из ИсходнаяТаблица Цикл
        ЗначениеГруппировки = СтрокаИсходной[ИмяКолонкиГруппировки];
        ЧисловоеЗначение = СтрокаИсходной[ИмяЧисловойКолонки];
        Если СоответствиеСумм[ЗначениеГруппировки] = Неопределено Тогда
            СоответствиеСумм[ЗначениеГруппировки] = ЧисловоеЗначение;
        Иначе
            СоответствиеСумм[ЗначениеГруппировки] = СоответствиеСумм[ЗначениеГруппировки] + ЧисловоеЗначение;
        КонецЕсли;
    КонецЦикла;

    Для Каждого КлючЗначение Из СоответствиеСумм Цикл
        НоваяСтрока = НоваяТаблица.Добавить();
        НоваяСтрока.ЗначениеГруппировки = КлючЗначение.Ключ;
        НоваяСтрока.Сумма = КлючЗначение.Значение;
    КонецЦикла;

    Возврат НоваяТаблица;
