Функция ГруппировкаТаблицы(ТаблицаЗначений, ИмяКолонкиГруппировки, ИмяКолонкиСуммирования)

	НоваяТаблица = Новый ТаблицаЗначений;
	НоваяТаблица.Колонки.Добавить("Группа");
	НоваяТаблица.Колонки.Добавить("Сумма");

	Для Каждого СтрокаТЗ Из ТаблицаЗначений Цикл
		ЗначениеГруппы = СтрокаТЗ[ИмяКолонкиГруппировки];
		Найден = Ложь;
		Для Каждого СтрокаНовой Из НоваяТаблица Цикл
			Если СтрокаНовой.Группа = ЗначениеГруппы Тогда
				СтрокаНовой.Сумма = СтрокаНовой.Сумма + СтрокаТЗ[ИмяКолонкиСуммирования];
				Найден = Истина;
				Прервать;
			КонецЕсли;
		КонецЦикла;

		Если Не Найден Тогда
			НовСтр = НоваяТаблица.Добавить();
			НовСтр.Группа = ЗначениеГруппы;
			НовСтр.Сумма = СтрокаТЗ[ИмяКолонкиСуммирования];
		КонецЕсли;

	КонецЦикла;

	Возврат НоваяТаблица;

