Функция СгруппироватьТаблицуЗначений(ИсходнаяТаблица, ИмяКолонкиГруппировки, ИмяКолонкиСуммы)
	// Не менять исходную таблицу
	Если Не ЗначениеЗаполнено(ИсходнаяТаблица) Тогда
		Возврат Новый ТаблицаЗначений;
	КонецЕсли;

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить(ИмяКолонкиГруппировки);
	Результат.Колонки.Добавить(ИмяКолонкиСуммы);

	Соотв = Новый Соответствие;

	// Сбор сумм по ключам
	Для Каждого Строка Из ИсходнаяТаблица Цикл
		Ключ = Строка[ИмяКолонкиГруппировки];
		ЗначСуммы = Строка[ИмяКолонкиСуммы];
		Если Не ЗначениеЗаполнено(ЗначСуммы) Тогда
			ЗначСуммы = 0;
		КонецЕсли;
		Если Соотв.Содержит(Ключ) Тогда
			Соотв.Вставить(Ключ, Соотв.Получить(Ключ) + ЗначСуммы);
		Иначе
			Соотв.Вставить(Ключ, ЗначСуммы);
		КонецЕсли;
	КонецЦикла;

	// Заполнение результирующей таблицы
	Ключи = Соотв.Ключи();
	Для Каждого Ключ Из Ключи Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока[ИмяКолонкиГруппировки] = Ключ;
		НоваяСтрока[ИмяКолонкиСуммы] = Соотв.Получить(Ключ);
	КонецЦикла;

	Возврат Результат;
КонецФункции

Функция ГруппироватьИСуммировать(ТаблицаЗначений, ИмяКолонкиГруппы, ИмяКолонкиСуммы) Экспорт
    // Создаём словарь для накопления сумм
    СловарьСумм = Новый Словарь;

    // Проходим по исходной таблице
    Для Каждого Строка Из ТаблицаЗначений Цикл
        Ключ = Строка[ИмяКолонкиГруппы];
        ЗначениеСуммы = Строка[ИмяКолонкиСуммы];

        Если НЕ СловарьСумм.СодержитКлюч(Ключ) Тогда
            СловарьСумм.Вставить(Ключ, 0);
        КонецЕсли;

        ТекущаяСумма = СловарьСумм.Получить(Ключ);
        СловарьСумм.Установить(Ключ, ТекущаяСумма + ЗначениеСуммы);
    КонецЦикла;

    // Формируем результирующую таблицу
    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Группа", Новый ОписаниеТипов("Строка"));
    Результат.Колонки.Добавить("Сумма", Новый ОписаниеТипов("Число"));

    // Заполняем её данными из словаря
    Для Каждого Ключ Из СловарьСумм.Ключи() Цикл
        НоваяСтрока = Результат.Добавить();
        НоваяСтрока.Группа = Ключ;
        НоваяСтрока.Сумма = СловарьСумм.Получить(Ключ);
    КонецЦикла;

    Возврат Результат;
КонецФункции.

