	РезультирующаяТаблица.Очистить();

	РезультирующаяТаблица.Колонки.Очистить();
	РезультирующаяТаблица.Колонки.Добавить(ИмяКолонкиГруппировки, ИсходнаяТаблица.Колонки[ИмяКолонкиГруппировки].ТипЗначений);
	РезультирующаяТаблица.Колонки.Добавить(ИмяЧисловойКолонки, ИсходнаяТаблица.Колонки[ИмяЧисловойКолонки].ТипЗначений);

