		НайденныеСтроки = РезультирующаяТаблица.НайтиСтроки(СтруктураОтбора);

		Если НайденныеСтроки.Количество() > 0 Тогда
			НайденнаяСтрока = НайденныеСтроки[0];
			НайденнаяСтрока[ИмяЧисловойКолонки] = НайденнаяСтрока[ИмяЧисловойКолонки] + СтрокаТЗ[ИмяЧисловойКолонки];
		Иначе
			НоваяСтрока = РезультирующаяТаблица.Добавить();
			НоваяСтрока[ИмяКолонкиГруппировки] = СтрокаТЗ[ИмяКолонкиГруппировки];
			НоваяСтрока[ИмяЧисловойКолонки] = СтрокаТЗ[ИмяЧисловойКолонки];
		КонецЕсли;

	КонецЦикла;

	Возврат РезультирующаяТаблица;

