Функция ОбъединитьИнтервалы(Интервалы)
    Если Интервалы.Количество() = 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    Список = Новый СписокЗначений;
    Для Каждого Интервал Из Интервалы Цикл
        Список.Добавить(Интервал[0], Интервал);
    КонецЦикла;
    Список.СортироватьПоЗначению(НаправлениеСортировки.Возр);

    Отсортированные = Новый Массив;
    Для Каждого Элемент Из Список Цикл
        Отсортированные.Добавить(Элемент.Значение);
    КонецЦикла;

    Результат = Новый Массив;
    Текущий = Отсортированные[0];
    Для Индекс = 1 По Отсортированные.Количество() - 1 Цикл
        След = Отсортированные[Индекс];
        Если След[0] <= Текущий[1] Тогда
            Текущий[1] = Макс(Текущий[1], След[1]);
        Иначе
            Результат.Добавить(Текущий);
            Текущий = След;
        КонецЕсли;
    КонецЦикла;
    Результат.Добавить(Текущий);

    Возврат Результат;
