Функция МассивНепересекающихсяИнтервалов(Интервалы)

	// Проверка на пустой массив
	Если Не ЗначениеЗаполнено(Интервалы) Тогда
		Возврат {};
	КонецЕсли;

	// Сортируем интервалы по началу
	СортироватьПоПолю = Новый Структура;
	СортироватьПоПолю.Вставить("Поле", "Значение[0]");
	СортироватьПоПолю.Вставить("Направление", НаправлениеСортировки.Возрастание);
	Интервалы.Сортировать(СортироватьПоПолю);

	Результат = {};
	ТекущийИнтервал = Интервалы[0];

