			ТекНач = Нач;
			ТекКон = Кон;
		КонецЕсли;
	КонецЦикла;

	Н = Новый Массив;
	Н.Добавить(ТекНач);
	Н.Добавить(ТекКон);
	Результат.Добавить(Н);

