        Для j = 0 По Отсортированные.ВГраница() - 1 - i Цикл
            Если Отсортированные[j][0] > Отсортированные[j + 1][0] Тогда
                Временный = Отсортированные[j];
                Отсортированные[j] = Отсортированные[j + 1];
                Отсортированные[j + 1] = Временный;
            КонецЕсли;
        КонецЦикла;
    КонецЦикла;

    // Объединение пересекающихся и соприкасающихся интервалов
    Результат = Новый Массив;
    ТекущееНачало = Отсортированные[0][0];
    ТекущийКонец = Отсортированные[0][1];

