    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    // Создаём матрицу (Длина1+1) x (Длина2+1)
    Матрица = Новый Массив(Длина1 + 1);
    Для и = 0 По Длина1 Цикл
        Матрица[и] = Новый Массив(Длина2 + 1, 0);
