		ПредыдущаяСтрока.Добавить(ИндексВторойСтроки);
		ТекущаяСтрока.Добавить(0);
	КонецЦикла;

	Для ИндексПервойСтроки = 1 По ДлинаПервойСтроки Цикл

		ТекущаяСтрока[0] = ИндексПервойСтроки;
		СимволПервойСтроки = Сред(ПерваяСтрока, ИндексПервойСтроки, 1);

		Для ИндексВторойСтроки = 1 По ДлинаВторойСтроки Цикл

			Если СимволПервойСтроки = Сред(ВтораяСтрока, ИндексВторойСтроки, 1) Тогда
				СтоимостьЗамены = 0;
			Иначе
				СтоимостьЗамены = 1;
			КонецЕсли;

			СтоимостьУдаления = ПредыдущаяСтрока[ИндексВторойСтроки] + 1;
			СтоимостьВставки = ТекущаяСтрока[ИндексВторойСтроки - 1] + 1;
			СтоимостьЗаменыСимвола = ПредыдущаяСтрока[ИндексВторойСтроки - 1] + СтоимостьЗамены;

			ТекущаяСтрока[ИндексВторойСтроки] = Мин(СтоимостьУдаления, СтоимостьВставки, СтоимостьЗаменыСимвола);

		КонецЦикла;

		ВременнаяСтрока = ПредыдущаяСтрока;
		ПредыдущаяСтрока = ТекущаяСтрока;
		ТекущаяСтрока = ВременнаяСтрока;

	КонецЦикла;

