	ПредыдущаяСтрока = Новый Массив(ДлинаВторойСтроки + 1);
	ТекущаяСтрока = Новый Массив(ДлинаВторойСтроки + 1);

	Для НомерСимвола = 0 По ДлинаВторойСтроки Цикл
		ПредыдущаяСтрока[НомерСимвола] = НомерСимвола;
	КонецЦикла;

	Для НомерПервогоСимвола = 1 По ДлинаПервойСтроки Цикл

		ТекущаяСтрока[0] = НомерПервогоСимвола;
		ПервыйСимвол = Сред(ПерваяСтрока, НомерПервогоСимвола, 1);

		Для НомерВторогоСимвола = 1 По ДлинаВторойСтроки Цикл

			ВторойСимвол = Сред(ВтораяСтрока, НомерВторогоСимвола, 1);

			Если ПервыйСимвол = ВторойСимвол Тогда
				СтоимостьЗамены = 0;
			Иначе
				СтоимостьЗамены = 1;
			КонецЕсли;

			СтоимостьУдаления = ПредыдущаяСтрока[НомерВторогоСимвола] + 1;
			СтоимостьВставки = ТекущаяСтрока[НомерВторогоСимвола - 1] + 1;
			СтоимостьЗаменыСимвола = ПредыдущаяСтрока[НомерВторогоСимвола - 1] + СтоимостьЗамены;

			МинимальнаяСтоимость = СтоимостьУдаления;

			Если СтоимостьВставки < МинимальнаяСтоимость Тогда
				МинимальнаяСтоимость = СтоимостьВставки;
			КонецЕсли;

			Если СтоимостьЗаменыСимвола < МинимальнаяСтоимость Тогда
				МинимальнаяСтоимость = СтоимостьЗаменыСимвола;
			КонецЕсли;

			ТекущаяСтрока[НомерВторогоСимвола] = МинимальнаяСтоимость;

		КонецЦикла;

		БуфернаяСтрока = ПредыдущаяСтрока;
		ПредыдущаяСтрока = ТекущаяСтрока;
		ТекущаяСтрока = БуфернаяСтрока;

	КонецЦикла;

	Возврат ПредыдущаяСтрока[ДлинаВторойСтроки];

