Функция РасстояниеЛевенштейна(Знач Строка1, Знач Строка2)

	Длина1 = СтрДлина(Строка1);
	Длина2 = СтрДлина(Строка2);

	Если Длина1 = 0 Тогда
		Возврат Длина2;
	КонецЕсли;

	Если Длина2 = 0 Тогда
		Возврат Длина1;
	КонецЕсли;

	СтрокаПред = Новый Массив(Длина2 + 1);
	СтрокаСлед = Новый Массив(Длина2 + 1);

	Для Индекс2 = 0 По Длина2 Цикл
		СтрокаПред[Индекс2] = Индекс2;
	КонецЦикла;

	Для Индекс1 = 1 По Длина1 Цикл
		СтрокаСлед[0] = Индекс1;
		Символ1 = Сред(Строка1, Индекс1, 1);

		Для Индекс2 = 1 По Длина2 Цикл
			Символ2 = Сред(Строка2, Индекс2, 1);
			ЦенаЗамены = ?(Символ1 = Символ2, 0, 1);

			СтрокаСлед[Индекс2] = Мин(
				СтрокаСлед[Индекс2 - 1] + 1,
				Мин(
					СтрокаПред[Индекс2] + 1,
					СтрокаПред[Индекс2 - 1] + ЦенаЗамены
				)
			);
		КонецЦикла;

		Для Индекс2 = 0 По Длина2 Цикл
			СтрокаПред[Индекс2] = СтрокаСлед[Индекс2];
