    Длина2 = СтрДлина(Строка2);

    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    // Инициализация двух строк для экономии памяти вместо полной матрицы
    ПредыдущаяСтрока = Новый Массив(Длина2 + 1);
    ТекущаяСтрока = Новый Массив(Длина2 + 1);

    Для j = 0 По Длина2 Цикл
        ПредыдущаяСтрока[j] = j;
    КонецЦикла;

    Для i = 1 По Длина1 Цикл
        ТекущаяСтрока[0] = i;
        Символ1 = Сред(Строка1, i, 1);

        Для j = 1 По Длина2 Цикл
            Символ2 = Сред(Строка2, j, 1);

            Если Символ1 = Символ2 Тогда
                ЦенаЗамены = 0;
            Иначе
                ЦенаЗамены = 1;
            КонецЕсли;

            Минимум = Мин(ПредыдущаяСтрока[j] + 1, ТекущаяСтрока[j - 1] + 1);
            ТекущаяСтрока[j] = Мин(Минимум, ПредыдущаяСтрока[j - 1] + ЦенаЗамены);
