Процедура СортироватьМассив(Массив)
	Для i = 0 По Массив.Количество() - 2 Цикл
		Для j = i + 1 По Массив.Количество() - 1 Цикл
			Если Массив[i] > Массив[j] Тогда
				ВременнаяПеременная = Массив[i];
				Массив[i] = Массив[j];
				Массив[j] = ВременнаяПеременная;
			КонецЕсли;
		КонецЦикла;
	КонецЦикла;
