            Если Массив[Индекс1] > Массив[Индекс2] Тогда
                ВременноеЗначение = Массив[Индекс1];
                Массив[Индекс1] = Массив[Индекс2];
                Массив[Индекс2] = ВременноеЗначение;
            КонецЕсли;
        КонецЦикла;
