Функция ЯвляетсяАнаграммой(Строка1, Строка2)

    // Приводим к нижнему регистру и удаляем пробелы
    Строка1 = НРег(СтрЗаменить(Строка1, " ", ""));
    Строка2 = НРег(СтрЗаменить(Строка2, " ", ""));

    // Если длины не равны - не анаграммы
    Если СтрДлина(Строка1) <> СтрДлина(Строка2) Тогда
        Возврат Ложь;
    КонецЕсли;

    // Подсчитываем количество каждого символа через структуру
    Символы1 = Новый Структура;
    Символы2 = Новый Структура;

    Для Индекс = 1 По СтрДлина(Строка1) Цикл
        Символ = Сред(Строка1, Индекс, 1);
        ИмяСимвола = "_" + КодСимвла(Символ);
        Если Символы1.Свойство(ИмяСимвола) Тогда
            Символы1[ИмяСимвола] = Символы1[ИмяСимвола] + 1;
        Иначе
            Символы1.Вставить(ИмяСимвола, 1);
        КонецЕсли;
    КонецЦикла;

    Для Индекс = 1 По СтрДлина(Строка2) Цикл
        Символ = Сред(Строка2, Индекс, 1);
        ИмяСимвола = "_" + КодСимвла(Символ);
        Если Символы2.Свойство(ИмяСимвола) Тогда
