        Иначе
            Символы2.Вставить(ИмяСимвола, 1);
        КонецЕсли;
    КонецЦикла;

    // Сравниваем количество каждого символа
    Для Каждого КлючЗначение Из Символы1 Цикл
        Если НЕ Символы2.Свойство(КлючЗначение.Ключ) Тогда
            Возврат Ложь;
        КонецЕсли;
        Если Символы2[КлючЗначение.Ключ] <> КлючЗначение.Значение Тогда
            Возврат Ложь;
        КонецЕсли;
