Функция ПолучитьПростыеЧисла(Граница) Экспорт

    Результат = Новый Массив;

    Если Граница < 2 Тогда
        Возврат Результат;
    КонецЕсли;

    // Создаем массив флагов (булево), заполненный Истина
    // Индекс массива соответствует числу
    ДлинаМассива = Граница + 1;
    Решето = Новый Массив(ДлинаМассива);
    Для Индекс = 0 По ДлинаМассива - 1 Цикл
        Решето[Индекс] = Истина;
    КонецЦикла;

    Решето[0] = Ложь;
    Решето[1] = Ложь;

    КвадратныйКорень = Окр(КорьКв(Граница), 0, РежимОкругления.Традиционный);
    Если КвадратныйКорень * КвадратныйКорень < Граница Тогда
        КвадратныйКорень = КвадратныйКорень + 1;
    КонецЕсли;

    Для Текущее = 2 По Граница Цикл
        Если Решето[Текущее] Тогда
            Если Текущее <= КвадратныйКорень Тогда
                Множитель = Текущее * Текущее;
                Пока Множитель <= Граница Цикл
                    Решето[Множитель] = Ложь;
                    Множитель = Множитель + Текущее;
                КонецЦикла;
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Для Индекс = 2 По Граница Цикл
        Если Решето[Индекс] Тогда
            Результат.Добавить(Индекс);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;

КонецФункции
